INSERT INTO organizations (external_key, slug, status, source_status, entity_type, visibility_public, source_locked, review_flags_json, source_format_json, legacy_sections_json) VALUES ('org_akseso', 'akseso', 'published', 'submitted', 'organisation', 1, 1, NULL, '{"general_information":{},"service_offer":{},"access_and_referral":{},"practical_information":{},"professional_information":{}}', '{"youth_sections":[{"title":{"nl":"Wie zijn wij?"},"paragraphs":[{"nl":"Akseso is een plek op Bonaire waar kinderen, jongeren, ouders en gezinnen terechtkunnen als ze hulp of advies nodig hebben."},{"nl":"We luisteren naar wat er speelt en zoeken samen naar oplossingen. Het doel is dat iedereen zich veilig, gezond en fijn voelt. Akseso helpt zo vroeg mogelijk, zodat problemen niet groter worden."}]},{"title":{"nl":"Voor wie zijn wij?"},"items":["Kinderen","Jongeren","Ouders en verzorgers","Gezinnen","Mensen die hulp of advies nodig hebben"]},{"title":{"nl":"Waarmee kunnen wij helpen?"},"items":["Problemen thuis","Verdrietig, boos of onzeker voelen","Zorgen over jezelf of iemand anders","Vragen over opgroeien of opvoeden","Geldproblemen of schulden in het gezin","Ruzie, geweld of onveilige situaties thuis","Hulp bij verlies of verdriet"]},{"title":{"nl":"Hoe kom je terecht?"},"paragraphs":[{"nl":"Je kunt zelf contact opnemen met Akseso. Ook een ouder, verzorger, leerkracht, huisarts of andere hulpverlener kan je aanmelden."}]},{"title":{"nl":"Hoe helpen wij?"},"items":["We maken eerst kennis met je.","We luisteren naar jouw verhaal.","Samen kijken we wat je nodig hebt.","We maken een plan.","Je krijgt hulp of we zoeken samen iemand die je verder kan helpen."]},{"title":{"nl":"Met wie werken wij samen?"},"paragraphs":[{"nl":"Akseso werkt samen met scholen, huisartsen, kinderopvang, hulpverleners en andere organisaties op Bonaire. Zo kunnen we ervoor zorgen dat jij de juiste hulp krijgt."}]},{"title":{"nl":"Contact"},"paragraphs":[{"nl":"Adres: Kaya Prinses Marie 7, Kralendijk, Bonaire. Telefoon: +599 717 7300. E-mail: info@aksesobon.com."},{"nl":"Loket Aksesibel inlooptijden: maandag, dinsdag en donderdag 08.00-11.00 uur; woensdag 13.00-16.00 uur; vrijdag op afspraak. Algemene openingstijden: maandag t/m vrijdag 08.00-17.00 uur."}]}],"professional_sections":[{"title":{"nl":"Algemene informatie"},"paragraphs":[{"nl":"Sentro Akseso Boneiru is de centrale organisatie voor sociale hulpverlening, preventie en ondersteuning op Bonaire."},{"nl":"De organisatie biedt laagdrempelige hulp bij opvoeding, gezin, welzijn, psychosociale problematiek, financiele problemen, gezondheid en veiligheid. Akseso wil inwoners tijdig passende ondersteuning bieden, zelfredzaamheid versterken en problemen voorkomen of vroegtijdig aanpakken."}]},{"title":{"nl":"Doelgroep"},"items":["Kinderen en jongeren","Ouders en gezinnen","Volwassenen","Kwetsbare inwoners","Professionals die advies of ondersteuning zoeken rondom jeugd en gezin"]},{"title":{"nl":"Hulpaanbod / dienstverlening"},"items":["Maatschappelijk werk","Jeugdgezondheidszorg","Opvoedingsondersteuning","Budget- en schuldhulpbegeleiding","Verlies- en relatiebegeleiding","Preventie en wijkontwikkeling","Advies- en meldpunt Huiselijk Geweld en Kindermishandeling (Guiami)","Zorg- en Veiligheidshuis Bonaire","Ondersteuning kinderopvang en kwaliteitszorg kinderopvang","Doorverwijzing naar gespecialiseerde hulpverlening"]},{"title":{"nl":"Werkwijze en methodieken"},"paragraphs":[{"nl":"Akseso werkt vraaggericht en integraal. Er wordt gebruikgemaakt van intake- en vraagverhelderingsgesprekken, systeemgericht werken, preventieve interventies, outreachend werken in wijken, scholen en kinderopvang, casusoverleg met ketenpartners en maatwerkbegeleiding afgestemd op de hulpvraag."}]},{"title":{"nl":"Trajectverloop en duur"},"paragraphs":[{"nl":"De duur varieert per hulpvraag. Kortdurende begeleiding kan enkele gesprekken omvatten; complexere situaties kunnen meerdere maanden ondersteuning vragen."}],"items":["Aanmelding of verwijzing","Intake en vraagverheldering","Analyse van de situatie","Opstellen van doelen en ondersteuningsplan","Begeleiding, ondersteuning of verwijzing","Evaluatie en afsluiting"]},{"title":{"nl":"Verwijzing en toegankelijkheid"},"paragraphs":[{"nl":"Een verwijzing is niet noodzakelijk. Inwoners kunnen zichzelf rechtstreeks aanmelden. Aanmelding via huisarts, school of andere professional is ook mogelijk."}]},{"title":{"nl":"Praktische informatie"},"paragraphs":[{"nl":"Adres: Kaya Prinses Marie 7, Kralendijk, Bonaire. Telefoon: +599 717 7300. E-mail: info@aksesobon.com."},{"nl":"Loket Aksesibel: maandag, dinsdag en donderdag 08.00-11.00 uur; woensdag 13.00-16.00 uur; vrijdag op afspraak. Algemene openingstijden: maandag t/m vrijdag 08.00-17.00 uur."}]},{"title":{"nl":"Samenwerkingspartners"},"items":["Huisartsen","Scholen","Kinderopvangorganisaties","Jeugd- en zorginstellingen","Openbaar Lichaam Bonaire","Zorg- en Veiligheidshuis","Politie en justitiele partners","Maatschappelijke organisaties op Bonaire"]},{"title":{"nl":"Aanvullende informatie voor hulpverleners"},"paragraphs":[{"nl":"Akseso fungeert als centraal toegangspunt voor sociale hulpverlening op Bonaire. De organisatie werkt multidisciplinair en integraal, met nadruk op preventie, vroegsignalering en versterking van gezinnen. Professionals kunnen cli?nten rechtstreeks aanmelden of overleggen over passende ondersteuning."}]}]}') ON DUPLICATE KEY UPDATE slug = VALUES(slug), status = VALUES(status), source_status = VALUES(source_status), entity_type = VALUES(entity_type), visibility_public = VALUES(visibility_public), source_locked = VALUES(source_locked), review_flags_json = VALUES(review_flags_json), source_format_json = VALUES(source_format_json), legacy_sections_json = VALUES(legacy_sections_json);
INSERT INTO organizations (external_key, slug, status, source_status, entity_type, visibility_public, source_locked, review_flags_json, source_format_json, legacy_sections_json) VALUES ('org_zjcn', 'zorg-en-jeugd-caribisch-nederland', 'published', 'submitted', 'organisation', 1, 1, NULL, '{"general_information":{},"service_offer":{},"access_and_referral":{},"practical_information":{},"professional_information":{}}', '{"youth_sections":[{"title":{"nl":"Wie zijn wij?"},"body":{"nl":"Wij zijn Jeugdzorg van Zorg en Jeugd Caribisch Nederland. Onze missie is: Elk kind een veilige plek."}},{"title":{"nl":"Waarmee kunnen wij helpen?"},"items":["Ondersteuning aan huis","Opvoedhulp","Pleegzorg","Begeleid wonen","Hulp bij problemen thuis, op school of in het dagelijks leven"]},{"title":{"nl":"Hoe kom je terecht?"},"body":{"nl":"Via huisarts, school, Guiami, Akseso of door zelf langs te komen tijdens inloopuren."}},{"title":{"nl":"Contact"},"body":{"nl":"Kaya Grandi 91. Telefoon: +599 715 8899. E-mail: info@jeugdzorgcn.com. Website: www.zorgenjeugdcn.nl. Openingstijden: ma/wo/vr 08.00-12.00 uur; di/do 13.00-16.30 uur."}}],"professional_sections":[{"title":{"nl":"Algemene informatie"},"body":{"nl":"ZJCN Afdeling Jeugdzorg zet zich in om de positie van het kind te verbeteren. De missie is: Elk kind een veilige plek."}},{"title":{"nl":"Hulpaanbod / dienstverlening"},"items":["Ambulante jeugdzorg","Pleegzorg","Begeleid wonen","Famia Fuerte","Opvoedhulp en gezinsondersteuning","Regievoering binnen reguliere trajecten"]},{"title":{"nl":"Verwijzing en toegankelijkheid"},"body":{"nl":"Doorverwijzing is passend bij opvoedproblematiek, jeugdproblematiek en behoefte aan buitenshuis wonen. Verwijzing kan via huisarts, school, Guiami of Akseso; inloop is ook mogelijk."}},{"title":{"nl":"Samenwerkingspartners"},"body":{"nl":"Huisartsen, Akseso, EOZ, Famia Fuerte, Fundashon Mariadal, OLB, FKPD, Guiami, Jeugdbescherming West, Jong Bonaire, KHF, KPCN, Tabitha, MHC, Reclassering, Stichting Project en Voogdijraad."}}]}') ON DUPLICATE KEY UPDATE slug = VALUES(slug), status = VALUES(status), source_status = VALUES(source_status), entity_type = VALUES(entity_type), visibility_public = VALUES(visibility_public), source_locked = VALUES(source_locked), review_flags_json = VALUES(review_flags_json), source_format_json = VALUES(source_format_json), legacy_sections_json = VALUES(legacy_sections_json);
INSERT INTO organizations (external_key, slug, status, source_status, entity_type, visibility_public, source_locked, review_flags_json, source_format_json, legacy_sections_json) VALUES ('org_eoz', 'expertisecenter-onderwijs-zorg-bonaire', 'published', 'submitted', 'organisation', 1, 1, NULL, '{"general_information":{},"service_offer":{},"access_and_referral":{},"practical_information":{},"professional_information":{}}', '{"youth_sections":[{"title":{"nl":"Wie zijn wij?"},"paragraphs":[{"nl":"EOZ helpt kinderen en jongeren op Bonaire om fijn naar school te gaan en goed te kunnen leren. EOZ vindt dat ieder kind belangrijk is: Tur mucha ta konta, elk kind telt."}]},{"title":{"nl":"Voor wie zijn wij?"},"items":["Kinderen op de basisschool","Jongeren op de middelbare school","Studenten van het mbo","Volwassenen die onderwijs volgen","Jonge kinderen vanaf 4 maanden via kinderopvang en voorschoolse ondersteuning"]},{"title":{"nl":"Waarmee kunnen wij helpen?"},"paragraphs":[{"nl":"Soms heeft een leerling extra hulp nodig op school. EOZ helpt dan samen met school, ouders en andere hulpverleners."}],"items":["Leerkrachten en scholen helpen om leerlingen beter te ondersteunen","Extra hulp geven aan leerlingen die dat nodig hebben","Groepsactiviteiten, workshops en coaching organiseren","Speciale ondersteuning bieden voor leerlingen met grotere uitdagingen","Samenwerken met andere organisaties om de juiste hulp te regelen"]},{"title":{"nl":"Hoe kom je terecht?"},"paragraphs":[{"nl":"Als leren op school moeilijk gaat, kan school dit bespreken met ouders. Met toestemming van ouders kan de leerling worden aangemeld bij EOZ. Daarna kijken EOZ, school, ouders en leerling samen wat nodig is."}]},{"title":{"nl":"Hoe helpen wij?"},"items":["We kijken samen met school en ouders wat een kind nodig heeft.","We maken een plan om het kind te helpen op school.","We geven tips en advies aan juffen, meesters, leerkrachten en docenten.","We helpen kinderen soms een-op-een.","We organiseren speciale lessen of activiteiten in een groep.","We werken samen met andere hulpverleners als dat nodig is."]},{"title":{"nl":"Contact"},"paragraphs":[{"nl":"Adres: Kaya Sonmontuno 8. Telefoon: +599 717 4144. E-mail: info@eoz-bonaire.org. Website: www.eoz.org. Openingstijden: 07.30-16.30 uur."}]}],"professional_sections":[{"title":{"nl":"Algemene informatie"},"paragraphs":[{"nl":"Het Expertisecenter Onderwijs Zorg Bonaire biedt ondersteuning en begeleiding aan leerlingen en studenten die door leer-, sociaal-emotionele of gedragsproblemen vast dreigen te lopen in het onderwijs."},{"nl":"EOZ biedt zorg in aanvulling op de zorg die al door school wordt geboden. De samenwerking tussen school en EOZ speelt hierbij een belangrijke rol."}]},{"title":{"nl":"Doelgroep"},"paragraphs":[{"nl":"Leerlingen in het basisonderwijs, voortgezet onderwijs, mbo en Forma. Vanaf schooljaar 2025-2026 ondersteunt EOZ ook vanaf vier maanden via kinderopvang, vroegsignalering en preventie, in samenwerking met Akseso, Consultatiebureau/GGD en Kinderpoli."}]},{"title":{"nl":"Hulpaanbod / dienstverlening"},"items":["Ondersteunen van basiszorg op scholen via het zorgteam","Extra zorg aan school en leerlingen op maat via coaching, workshops en groepsactiviteiten","Specialistische zorg en voorzieningen in samenwerking met scholen","SEM-klas, samenwerking tussen school, EOZ en MHC","Kolegio Emmy Schermer voor leerlingen met intensieve behoefte","Verbinden van school en jeugdketenpartners voor begeleiding, hulp en coordinatie van onderwijszorg"]},{"title":{"nl":"Werkwijze en methodieken"},"items":["Handelingsgericht werken","Oplossingsgericht werken","Ambulante begeleiding van leerlingen met specifieke behoeften","Handelingsgerichte diagnostiek voor ondersteuningsplannen","Advisering en consultatie voor zorgteams, leerkrachten en docenten","Onderwijsondersteunende activiteiten gericht op inclusie","Training rond specialistische ondersteuning aan scholen en ketenpartners"]},{"title":{"nl":"Trajectverloop en duur"},"paragraphs":[{"nl":"Per schooljaar wordt per zorgleerling een handelingsgericht traject gemaakt. Het traject wordt uitgestippeld en besproken met school, ouders en leerling. Tijdens tussenevaluaties en de eindevaluatie wordt gezamenlijk besloten of het traject wordt afgesloten of voortgezet."}]},{"title":{"nl":"Verwijzing en toegankelijkheid"},"paragraphs":[{"nl":"Aanmelding gaat via school en ouders moeten toestemming geven om een leerling aan te melden bij EOZ. De aanmelding wordt digitaal aangeleverd en doorgaans binnen een week verwerkt en besproken, behalve rond feest- en vakantiedagen."}]},{"title":{"nl":"Praktische informatie"},"paragraphs":[{"nl":"Adres: Kaya Sonmontuno 8. Telefoon: +599 717 4144. E-mail: info@eoz-bonaire.org. Website: www.eoz.org. Openingstijden: 07.30-16.30 uur."}]}]}') ON DUPLICATE KEY UPDATE slug = VALUES(slug), status = VALUES(status), source_status = VALUES(source_status), entity_type = VALUES(entity_type), visibility_public = VALUES(visibility_public), source_locked = VALUES(source_locked), review_flags_json = VALUES(review_flags_json), source_format_json = VALUES(source_format_json), legacy_sections_json = VALUES(legacy_sections_json);
INSERT INTO organizations (external_key, slug, status, source_status, entity_type, visibility_public, source_locked, review_flags_json, source_format_json, legacy_sections_json) VALUES ('org_fundashon_forma', 'fundashon-forma', 'published', 'submitted', 'organisation', 1, 1, NULL, '{"general_information":{},"service_offer":{},"access_and_referral":{},"practical_information":{},"professional_information":{}}', '{"youth_sections":[{"title":{"nl":"Wie zijn wij?"},"body":{"nl":"Fundashon Forma helpt jongeren en volwassenen om nieuwe dingen te leren en zich verder te ontwikkelen."}},{"title":{"nl":"Waarmee kunnen wij helpen?"},"items":["Entreeonderwijs mbo niveau 1","Cursussen","Hulp bij lezen, schrijven en taal","Werkvaardigheden en zelfstandigheid","Long Life Learning voor jongeren van 18+ uit het VSO"]},{"title":{"nl":"Hoe kom je terecht?"},"body":{"nl":"Je kunt jezelf aanmelden of worden doorverwezen door school, een hulpverlener of een andere organisatie."}},{"title":{"nl":"Contact"},"body":{"nl":"Telefoon: +599 717-6949. E-mail: info@fundashonforma.com. Website: www.fundashonforma.com. Adres: Kaya Gavilan z/n. Openingstijden: maandag t/m vrijdag 08.00-16.00 uur."}}],"professional_sections":[{"title":{"nl":"Algemene informatie"},"body":{"nl":"Fundashon Forma is een onderwijs- en ontwikkelingsorganisatie voor persoonlijke, sociale en beroepsmatige ontwikkeling."}},{"title":{"nl":"Doelgroep"},"body":{"nl":"Jongvolwassenen en volwassenen zonder startkwalificatie, LVB-deelnemers, laaggeletterde volwassenen, 18+ VSO-studenten en organisaties die advies zoeken."}},{"title":{"nl":"Hulpaanbod / dienstverlening"},"items":["Entreeonderwijs mbo niveau 1","Vormingstrajecten","ALFA-onderwijs","Long Life Learning","Ondersteuning bij arbeidsvaardigheden en zelfredzaamheid","Advisering aan organisaties"]},{"title":{"nl":"Trajectverloop en duur"},"body":{"nl":"MIFO: 1 jaar. Entreeopleiding: 1 jaar. ALFA en LLL: maatwerk afhankelijk van leerdoelen en ontwikkelbehoefte."}}]}') ON DUPLICATE KEY UPDATE slug = VALUES(slug), status = VALUES(status), source_status = VALUES(source_status), entity_type = VALUES(entity_type), visibility_public = VALUES(visibility_public), source_locked = VALUES(source_locked), review_flags_json = VALUES(review_flags_json), source_format_json = VALUES(source_format_json), legacy_sections_json = VALUES(legacy_sections_json);
INSERT INTO organizations (external_key, slug, status, source_status, entity_type, visibility_public, source_locked, review_flags_json, source_format_json, legacy_sections_json) VALUES ('org_rebound', 'rebound', 'published', 'demo', 'organisation', 1, 1, '{"needs_content_review":true,"replace_with_official_format_when_available":true}', '{"general_information":{},"service_offer":{},"access_and_referral":{},"practical_information":{},"professional_information":{}}', '{"youth_sections":[],"professional_sections":[]}') ON DUPLICATE KEY UPDATE slug = VALUES(slug), status = VALUES(status), source_status = VALUES(source_status), entity_type = VALUES(entity_type), visibility_public = VALUES(visibility_public), source_locked = VALUES(source_locked), review_flags_json = VALUES(review_flags_json), source_format_json = VALUES(source_format_json), legacy_sections_json = VALUES(legacy_sections_json);
INSERT INTO organizations (external_key, slug, status, source_status, entity_type, visibility_public, source_locked, review_flags_json, source_format_json, legacy_sections_json) VALUES ('org_mhc', 'mental-health-caribbean', 'published', 'submitted', 'organisation', 1, 1, NULL, '{"general_information":{},"service_offer":{},"access_and_referral":{},"practical_information":{},"professional_information":{}}', '{"youth_sections":[{"title":{"nl":"Wie zijn wij?"},"paragraphs":[{"nl":"Mental Health Caribbean helpt kinderen, jongeren en hun gezinnen als het niet goed gaat met gevoelens, gedachten of gedrag."},{"nl":"Op Bonaire kunnen kinderen en jongeren terecht bij behandelcentrum Hi-5. Ook op Saba en Sint Eustatius biedt MHC hulp aan kinderen en jongeren."}]},{"title":{"nl":"Voor wie zijn wij?"},"paragraphs":[{"nl":"MHC is er voor kinderen en jongeren van 0 tot 18 jaar en hun ouders of verzorgers."}]},{"title":{"nl":"Waarmee kunnen wij helpen?"},"items":["Vaak bang of zenuwachtig zijn","Verdrietig of somber voelen","Snel boos worden","Moeite met opletten of concentreren","Slecht slapen of moeilijk eten","Problemen met vrienden, familie of school","Iets vervelends hebben meegemaakt","Moeite met gamen, alcohol of drugs"]},{"title":{"nl":"Hoe kom je terecht?"},"paragraphs":[{"nl":"Om hulp bij MHC te krijgen, heb je een verwijzing nodig van een huisarts of kinderarts. Daarna wordt een afspraak gemaakt voor een eerste gesprek."}]},{"title":{"nl":"Hoe helpen wij?"},"paragraphs":[{"nl":"MHC kijkt niet alleen naar jou, maar ook naar de mensen om je heen, zoals ouders, verzorgers en soms school. Samen zoeken jullie naar wat nodig is."}],"items":["Gesprekken met een psycholoog","Therapie","Groepstraining","Begeleiding samen met je gezin"]},{"title":{"nl":"Hoelang duurt de hulp?"},"paragraphs":[{"nl":"Een traject verloopt meestal in stappen: kennismaken, onderzoeken, behandelen en afronden. Bij afronding wordt besproken welke hulp of ondersteuning eventueel nog nodig is."}]},{"title":{"nl":"Contact"},"paragraphs":[{"nl":"Website: www.mentalhealthcaribbean.com. Telefoon: +599 717 0125, na het taalkeuzemenu #4 voor Hi-5. E-mail: secretariaat@mentalhealthcaribbean.com. Bezoekadres: MHC Kind & Jeugd Bonaire / Hi-5, Kaya Mendelssohn z/n. Locatie open: 08.00-12.00 en 13.00-14.00 uur. Telefonisch bereikbaar: 07.30-21.00 uur."}]}],"professional_sections":[{"title":{"nl":"Algemene informatie"},"paragraphs":[{"nl":"MHC Kind & Jeugd heeft als ambitie dat alle kinderen en jeugdigen een eerlijke kans krijgen om zich zo goed mogelijk te ontwikkelen tot veerkrachtige volwassenen."},{"nl":"MHC verzorgt geestelijke gezondheidszorg voor kinderen en jeugdigen op Bonaire, Saba en Sint Eustatius. Op Bonaire is de zorg uitgebreid met behandelcentrum Hi-5."}]},{"title":{"nl":"Doelgroep"},"paragraphs":[{"nl":"Kinderen en jongeren van 0 tot 18 jaar met psychische of psychiatrische klachten, en hun gezin."}]},{"title":{"nl":"Hulpaanbod / dienstverlening"},"items":["Ambulante diagnostiek","Behandeling en begeleiding","Individuele behandeling","Groepsbehandeling","Gezinsbehandeling","Ondersteuning bij angst, somberheid, boosheid, concentratieproblemen, eet- en slaapproblemen, omgangsproblemen, hechting, trauma en verslaving"]},{"title":{"nl":"Werkwijze en methodieken"},"paragraphs":[{"nl":"MHC Kind & Jeugd werkt vanuit een systemische benadering. Het hele gezin wordt betrokken bij onderzoek, begeleiding en behandeling. Alle relevante leefgebieden, zoals onderwijs, wonen, sociaal functioneren en dagbesteding, worden in kaart gebracht."}]},{"title":{"nl":"Trajectverloop en duur"},"items":["Intakefase: informatie verzamelen via gesprekken en observaties met kind en gezin","Onderzoeksfase: problemen of zorgen in kaart brengen via gesprekken, testen, observaties en andere methoden","Behandelfase: samen doelen benoemen en werken aan behandeling, individueel of met het gezin","Afronding en nazorg: bekijken hoe kind en gezin verder begeleid kunnen worden"]},{"title":{"nl":"Verwijzing en toegankelijkheid"},"paragraphs":[{"nl":"Voor behandeling bij MHC Kind & Jeugd is een verwijzing van huisarts of kinderarts nodig. Aanmelding gaat via de Bureaudienst om een intake in te plannen."}]},{"title":{"nl":"Praktische informatie"},"paragraphs":[{"nl":"Website: www.mentalhealthcaribbean.com. Telefoon: +599 717 0125, na taalkeuzemenu #4 voor Hi-5. E-mail: secretariaat@mentalhealthcaribbean.com. Bezoekadres: Kaya Mendelssohn z/n. Locatie open: 08.00-12.00 en 13.00-14.00 uur. Telefonisch bereikbaar: 07.30-21.00 uur."}]}]}') ON DUPLICATE KEY UPDATE slug = VALUES(slug), status = VALUES(status), source_status = VALUES(source_status), entity_type = VALUES(entity_type), visibility_public = VALUES(visibility_public), source_locked = VALUES(source_locked), review_flags_json = VALUES(review_flags_json), source_format_json = VALUES(source_format_json), legacy_sections_json = VALUES(legacy_sections_json);
INSERT INTO organizations (external_key, slug, status, source_status, entity_type, visibility_public, source_locked, review_flags_json, source_format_json, legacy_sections_json) VALUES ('org_ggd_bonaire', 'ggd-bonaire', 'published', 'demo', 'organisation', 1, 1, '{"needs_content_review":true,"replace_with_official_format_when_available":true}', '{"general_information":{},"service_offer":{},"access_and_referral":{},"practical_information":{},"professional_information":{}}', '{"youth_sections":[],"professional_sections":[]}') ON DUPLICATE KEY UPDATE slug = VALUES(slug), status = VALUES(status), source_status = VALUES(source_status), entity_type = VALUES(entity_type), visibility_public = VALUES(visibility_public), source_locked = VALUES(source_locked), review_flags_json = VALUES(review_flags_json), source_format_json = VALUES(source_format_json), legacy_sections_json = VALUES(legacy_sections_json);
INSERT INTO organizations (external_key, slug, status, source_status, entity_type, visibility_public, source_locked, review_flags_json, source_format_json, legacy_sections_json) VALUES ('org_fkpd', 'fundashon-kuido-pa-personanan-desabilita', 'published', 'demo', 'organisation', 1, 1, '{"needs_content_review":true,"replace_with_official_format_when_available":true}', '{"general_information":{},"service_offer":{},"access_and_referral":{},"practical_information":{},"professional_information":{}}', '{"youth_sections":[],"professional_sections":[]}') ON DUPLICATE KEY UPDATE slug = VALUES(slug), status = VALUES(status), source_status = VALUES(source_status), entity_type = VALUES(entity_type), visibility_public = VALUES(visibility_public), source_locked = VALUES(source_locked), review_flags_json = VALUES(review_flags_json), source_format_json = VALUES(source_format_json), legacy_sections_json = VALUES(legacy_sections_json);
INSERT INTO organizations (external_key, slug, status, source_status, entity_type, visibility_public, source_locked, review_flags_json, source_format_json, legacy_sections_json) VALUES ('org_kpcn', 'korps-politie-caribisch-nederland', 'published', 'demo', 'organisation', 1, 1, '{"needs_content_review":true,"replace_with_official_format_when_available":true}', '{"general_information":{},"service_offer":{},"access_and_referral":{},"practical_information":{},"professional_information":{}}', '{"youth_sections":[],"professional_sections":[]}') ON DUPLICATE KEY UPDATE slug = VALUES(slug), status = VALUES(status), source_status = VALUES(source_status), entity_type = VALUES(entity_type), visibility_public = VALUES(visibility_public), source_locked = VALUES(source_locked), review_flags_json = VALUES(review_flags_json), source_format_json = VALUES(source_format_json), legacy_sections_json = VALUES(legacy_sections_json);
INSERT INTO organizations (external_key, slug, status, source_status, entity_type, visibility_public, source_locked, review_flags_json, source_format_json, legacy_sections_json) VALUES ('org_voogdijraad_cn', 'voogdijraad-caribisch-nederland', 'published', 'demo', 'organisation', 1, 1, '{"needs_content_review":true,"replace_with_official_format_when_available":true}', '{"general_information":{},"service_offer":{},"access_and_referral":{},"practical_information":{},"professional_information":{}}', '{"youth_sections":[],"professional_sections":[]}') ON DUPLICATE KEY UPDATE slug = VALUES(slug), status = VALUES(status), source_status = VALUES(source_status), entity_type = VALUES(entity_type), visibility_public = VALUES(visibility_public), source_locked = VALUES(source_locked), review_flags_json = VALUES(review_flags_json), source_format_json = VALUES(source_format_json), legacy_sections_json = VALUES(legacy_sections_json);
INSERT INTO organizations (external_key, slug, status, source_status, entity_type, visibility_public, source_locked, review_flags_json, source_format_json, legacy_sections_json) VALUES ('org_reclassering_cn', 'reclassering-caribisch-nederland', 'published', 'submitted', 'organisation', 1, 1, NULL, '{"general_information":{},"service_offer":{},"access_and_referral":{},"practical_information":{},"professional_information":{}}', '{"youth_sections":[{"title":{"nl":"Wie zijn wij?"},"paragraphs":[{"nl":"Stichting Reclassering Caribisch Nederland helpt mee om Bonaire, Sint Eustatius en Saba veilig te houden. Reclassering begeleidt jongeren die problemen hebben gekregen met politie of rechter."}]},{"title":{"nl":"Voor wie zijn wij?"},"items":["Jongeren van 12 tot 21 jaar die iets hebben gedaan wat niet mag volgens de wet","Jongeren die vaak niet naar school zijn gegaan","Jongeren die van de rechter begeleiding moeten krijgen"]},{"title":{"nl":"Waarmee kunnen wij helpen?"},"paragraphs":[{"nl":"Een jeugdreclasseerder helpt jongeren om weer goede keuzes te maken. Samen wordt gekeken wat nodig is om problemen te voorkomen en de toekomst beter te maken. Afspraken kunnen verplicht zijn."}],"items":["Weer naar school gaan","Geen drugs gebruiken","Meedoen aan hulp of een training","Luisteren naar afspraken van de rechter"]},{"title":{"nl":"Hoe kom je terecht?"},"paragraphs":[{"nl":"Reclassering werkt in opdracht van de officier van justitie of rechter. Je kunt daarom niet zelf worden aangemeld."}]},{"title":{"nl":"Hoe helpen wij?"},"paragraphs":[{"nl":"Iedere jongere is anders. Daarom wordt samen een plan gemaakt dat past bij de situatie. Tijdens begeleiding wordt regelmatig gepraat, gekeken hoe het gaat en gewerkt aan doelen en meer zelfstandigheid."}]},{"title":{"nl":"Hoelang duurt de hulp?"},"paragraphs":[{"nl":"Dat verschilt per jongere en per justitieel kader. Soms duurt begeleiding een paar maanden, soms een of twee jaar."}]},{"title":{"nl":"Met wie werken wij samen?"},"items":["De jongere","Ouders of verzorgers","School","Hulpverleners","Andere organisaties die kunnen helpen"]},{"title":{"nl":"Contact"},"paragraphs":[{"nl":"Adres: Kaya L.D. Gerharts 8, Les Galleries Shopping Mall. Telefoon: +599 717 3288. E-mail: administratie@reclassering-cn.com. Website: https://www.reclassering-cn.com/. Openingstijden: maandag t/m vrijdag 08.00-12.00 en 13.00-17.00 uur."}]}],"professional_sections":[{"title":{"nl":"Algemene informatie"},"paragraphs":[{"nl":"Stichting Reclassering Caribisch Nederland werkt aan een veiligere samenleving door criminaliteit te voorkomen en recidive terug te dringen. Jeugdreclassering beschermt en bevordert de positieve ontwikkeling van jongeren."},{"nl":"In Caribisch Nederland wordt jeugdreclassering uitgevoerd door SRCN in samenwerking met ZJCN, na oplegging door de kinderrechter. De begeleiding is bedoeld voor jongeren van 12 tot 21 jaar tegen wie een proces-verbaal is opgemaakt."}]},{"title":{"nl":"Doelgroep"},"paragraphs":[{"nl":"Jongeren van 12 tot 21 jaar tegen wie een proces-verbaal is opgemaakt, bijvoorbeeld wegens een strafbaar feit of ernstig schoolverzuim."}]},{"title":{"nl":"Hulpaanbod / dienstverlening"},"paragraphs":[{"nl":"De jeugdreclasseerder werkt samen met de jongere, het gezin en betrokken ketenpartners om tot gedragsverandering te komen. Waar nodig wordt specialistische hulpverlening ingeschakeld."}]},{"title":{"nl":"Werkwijze en methodieken"},"paragraphs":[{"nl":"Er wordt gewerkt met de methodiek Werken in gedwongen kader en bij jeugdigen met de methodiek Jeugdreclassering zoals die ook in Europees Nederland wordt gehanteerd. Jeugdreclasseringswerkers worden getraind in de toepassing van elementen uit deze methodiek."}]},{"title":{"nl":"Trajectverloop en duur"},"paragraphs":[{"nl":"Trajectduur verschilt per kader. Jeugdreclassering als bijzondere voorwaarde bij vonnis varieert van zes maanden tot twee jaar. Toezicht en begeleiding bij schorsing van voorlopige hechtenis duurt gemiddeld een aantal weken tot maanden. Een voorwaardelijk sepot heeft een proeftijd van 1 jaar; een proeftijd bij vonnis is meestal 2 jaar."}]},{"title":{"nl":"Verwijzing en toegankelijkheid"},"paragraphs":[{"nl":"Reclassering werkt in opdracht van het OM, de rechter(-commissaris) of het ministerie van JenV. SRCN is geen hulpverleningsorganisatie; reguliere doorverwijzing naar de organisatie is daarom niet mogelijk."}]},{"title":{"nl":"Praktische informatie"},"paragraphs":[{"nl":"Telefoon: +599 717 3288. E-mail: administratie@reclassering-cn.com. Website: https://www.reclassering-cn.com/. Bezoekadres: Kaya L.D. Gerharts 8, Les Galleries Shopping Mall, Kralendijk. Openingstijden: maandag t/m vrijdag 08.00-12.00 en 13.00-17.00 uur."}]}]}') ON DUPLICATE KEY UPDATE slug = VALUES(slug), status = VALUES(status), source_status = VALUES(source_status), entity_type = VALUES(entity_type), visibility_public = VALUES(visibility_public), source_locked = VALUES(source_locked), review_flags_json = VALUES(review_flags_json), source_format_json = VALUES(source_format_json), legacy_sections_json = VALUES(legacy_sections_json);
INSERT INTO organizations (external_key, slug, status, source_status, entity_type, visibility_public, source_locked, review_flags_json, source_format_json, legacy_sections_json) VALUES ('org_jong_bonaire', 'jong-bonaire', 'published', 'submitted', 'organisation', 1, 1, NULL, '{"general_information":{},"service_offer":{},"access_and_referral":{},"practical_information":{},"professional_information":{}}', '{"youth_sections":[{"title":{"nl":"Wie zijn wij?"},"body":{"nl":"Jong Bonaire is een plek voor jongeren op Bonaire die op de middelbare school zitten."}},{"title":{"nl":"Waarmee kunnen wij helpen?"},"items":["Sportactiviteiten","Creatieve activiteiten","Educatieve activiteiten","Culturele activiteiten","Avond- en weekendactiviteiten","Zomerkampen"]},{"title":{"nl":"Contact"},"body":{"nl":"Telefoon: +599 717 4303. E-mail: generalmanager@jongbonaire.org. Adres: Kaya Libertador Simon Bolivar 16. Openingstijden: maandag t/m vrijdag 08.00-17.00 uur."}}],"professional_sections":[{"title":{"nl":"Algemene informatie"},"body":{"nl":"Stichting Jeugdwerk Jong Bonaire biedt een breed aanbod van sociale, educatieve, sportieve, recreatieve en culturele activiteiten."}},{"title":{"nl":"Doelgroep"},"body":{"nl":"Jongeren van 12 tot 18 jaar."}},{"title":{"nl":"Hulpaanbod / dienstverlening"},"body":{"nl":"Jong Bonaire is geen hulpverleningsinstantie, maar een openbare ontwikkelvoorziening waar jongeren terechtkunnen voor ondersteuning, ontwikkeling en begeleiding."}}]}') ON DUPLICATE KEY UPDATE slug = VALUES(slug), status = VALUES(status), source_status = VALUES(source_status), entity_type = VALUES(entity_type), visibility_public = VALUES(visibility_public), source_locked = VALUES(source_locked), review_flags_json = VALUES(review_flags_json), source_format_json = VALUES(source_format_json), legacy_sections_json = VALUES(legacy_sections_json);
INSERT INTO organizations (external_key, slug, status, source_status, entity_type, visibility_public, source_locked, review_flags_json, source_format_json, legacy_sections_json) VALUES ('org_rosa_di_sharon', 'fundashon-rosa-di-sharon', 'published', 'submitted', 'programme', 1, 1, NULL, '{"general_information":{},"service_offer":{},"access_and_referral":{},"practical_information":{},"professional_information":{}}', '{"youth_sections":[{"title":{"nl":"Wie zijn wij?"},"body":{"nl":"Kas pa Hoben ku Futuro (KHF) is een huis van Fundashon Rosa di Sharon waar meisjes en jonge vrouwen kunnen wonen als het thuis tijdelijk niet veilig is of extra hulp nodig is."}},{"title":{"nl":"Voor wie zijn wij?"},"items":["Meisjes van ongeveer 14 tot 21 jaar","Zwangere tieners","Jonge moeders die extra steun nodig hebben"]},{"title":{"nl":"Hoe kom je terecht?"},"body":{"nl":"Een plaatsing gebeurt altijd samen met ZJCN. ZJCN en KHF bekijken of KHF de juiste plek is."}},{"title":{"nl":"Contact"},"body":{"nl":"Adres: Kaminda Nieuw Amsterdam 5. KHF: 717 6858. Zorgmanager: 796 6858. E-mail: directie.fundashonrosadisharon@gmail.com. Openingstijden kantoor: maandag t/m vrijdag 08.30-16.30 uur."}}],"professional_sections":[{"title":{"nl":"Algemene informatie"},"body":{"nl":"Fundashon Rosa di Sharon biedt ondersteuning aan gezinnen. KHF is een kleinschalige woonvoorziening waar tienermeisjes tijdelijk of langer kunnen verblijven wanneer thuis wonen niet mogelijk of niet veilig is."}},{"title":{"nl":"Hulpaanbod / dienstverlening"},"items":["24-uurs woonbegeleiding","Individuele begeleiding","Gezinsbegeleiding","Ondersteuning gericht op ontwikkeling en zelfstandigheid","Samenwerking met ketenpartners binnen jeugdhulp"]},{"title":{"nl":"Werkwijze en methodieken"},"body":{"nl":"Er wordt gewerkt met competentievergroting, traumasensitief werken, Dushi-methodiek, emotieregulatie, 5-puntenmodel, 5G-schema en MIG-methodiek."}},{"title":{"nl":"Verwijzing en toegankelijkheid"},"body":{"nl":"ZJCN moet goedkeuring geven voor plaatsing."}},{"title":{"nl":"Samenwerkingspartners"},"body":{"nl":"ZJCN, MHC, Akseso, EOZ en scholen."}}]}') ON DUPLICATE KEY UPDATE slug = VALUES(slug), status = VALUES(status), source_status = VALUES(source_status), entity_type = VALUES(entity_type), visibility_public = VALUES(visibility_public), source_locked = VALUES(source_locked), review_flags_json = VALUES(review_flags_json), source_format_json = VALUES(source_format_json), legacy_sections_json = VALUES(legacy_sections_json);
INSERT INTO organizations (external_key, slug, status, source_status, entity_type, visibility_public, source_locked, review_flags_json, source_format_json, legacy_sections_json) VALUES ('org_tabitha', 'tabitha', 'published', 'demo', 'organisation', 1, 1, '{"needs_content_review":true,"replace_with_official_format_when_available":true}', '{"general_information":{},"service_offer":{},"access_and_referral":{},"practical_information":{},"professional_information":{}}', '{"youth_sections":[],"professional_sections":[]}') ON DUPLICATE KEY UPDATE slug = VALUES(slug), status = VALUES(status), source_status = VALUES(source_status), entity_type = VALUES(entity_type), visibility_public = VALUES(visibility_public), source_locked = VALUES(source_locked), review_flags_json = VALUES(review_flags_json), source_format_json = VALUES(source_format_json), legacy_sections_json = VALUES(legacy_sections_json);
INSERT INTO organizations (external_key, slug, status, source_status, entity_type, visibility_public, source_locked, review_flags_json, source_format_json, legacy_sections_json) VALUES ('org_stichting_project', 'stichting-project', 'published', 'submitted', 'programme', 1, 1, NULL, '{"general_information":{},"service_offer":{},"access_and_referral":{},"practical_information":{},"professional_information":{}}', '{"youth_sections":[{"title":{"nl":"Wie zijn wij?"},"paragraphs":[{"nl":"Stichting Project is een plek op Bonaire waar kinderen en jongeren hulp, begeleiding en een veilige omgeving krijgen wanneer het thuis, op school of in hun leven moeilijk gaat."},{"nl":"Bij Stichting Project mag je zijn wie je bent. Er wordt niet alleen gekeken naar wat misgaat, maar vooral naar wat jij nodig hebt, waar je goed in bent en hoe jij verder kunt groeien."}]},{"title":{"nl":"Voor wie zijn wij?"},"paragraphs":[{"nl":"Stichting Project is er voor kinderen en jongeren van de BES-eilanden van 8 tot en met 18 jaar."}],"items":["Kinderen en jongeren die veel moeilijke dingen hebben meegemaakt","Jongeren die vaak boos, verdrietig of bang zijn","Jongeren die moeite hebben met regels of gedrag","Jongeren met problemen thuis of op school","Jongeren die extra ondersteuning nodig hebben om zich goed te ontwikkelen"]},{"title":{"nl":"Waarmee kunnen wij helpen?"},"items":["Je niet veilig voelen","Vaak boos zijn of snel ruzie krijgen","Veel piekeren of bang zijn","Verdrietig zijn","Moeite hebben om anderen te vertrouwen","Problemen op school","Lastig met gevoelens omgaan","Leren sterker in het leven te staan"]},{"title":{"nl":"Hoe kom je terecht?"},"paragraphs":[{"nl":"Je kunt jezelf niet aanmelden voor wonen bij Stichting Project. Als je tijdelijk bij Stichting Project gaat wonen, verloopt de aanmelding via ZJCN. Voor de middagbehandeling kan aanmelding worden gedaan door ZJCN, MHC, EOZ of Akseso."}]},{"title":{"nl":"Hoe helpen wij?"},"paragraphs":[{"nl":"Stichting Project helpt door een veilige plek te bieden met rust, duidelijkheid en structuur. Samen wordt een plan gemaakt met doelen die bij jou passen."}],"items":["Minder boos worden","Beter omgaan met gevoelens","Meer zelfvertrouwen krijgen","Beter functioneren op school","Leren omgaan met moeilijke situaties"]},{"title":{"nl":"Hoelang duurt de hulp?"},"paragraphs":[{"nl":"Iedereen is anders. Gemiddeld duurt een begeleidingstraject ongeveer anderhalf jaar. Regelmatig wordt samen gekeken hoe het gaat en wat nog nodig is. Als het traject klaar is, wordt gekeken welke volgende stap het beste past."}]},{"title":{"nl":"Met wie werken wij samen?"},"items":["Ouders en verzorgers","Familieleden","Scholen","ZJCN","Akseso","MHC","EOZ","Rosa di Sharon","Begeleid Wonen","Jong Bonaire"]},{"title":{"nl":"Contact"},"paragraphs":[{"nl":"Adres: Bulevar Gobernador N. Debrot 218, Bonaire. Telefoon: 782-8481. E-mail: info@stichtingproject.com. Website: www.stichtingproject.com."}]}],"professional_sections":[{"title":{"nl":"Algemene informatie"},"paragraphs":[{"nl":"Stichting Project is een specialistische voorziening op Bonaire voor jeugdigen met complexe gedragsproblemen van de BES-eilanden."},{"nl":"De voorziening wil jeugdigen die in onveilige omstandigheden opgroeien een nieuw perspectief bieden, vanuit passie, professionaliteit en samenwerking met jeugdigen en opvoeders. De missie is bijdragen aan een veilige, gezonde en kansrijke ontwikkeling van jeugdigen op de BES-eilanden."}]},{"title":{"nl":"Doelgroep"},"paragraphs":[{"nl":"Jeugdigen van 8 tot 18 jaar met ernstige en meervoudige problematiek. Het gaat om kinderen en jongeren bij wie eerdere hulpverlening onvoldoende effect had en die intensieve, specialistische ondersteuning nodig hebben."},{"nl":"Vaak is sprake van een combinatie van psychosociale en gedragsproblemen, gezins- en opvoedingsproblemen, leer- en ontwikkelingsachterstanden, gezondheidsproblemen en problemen in de sociale omgeving. Voor jeugdigen van Saba en Sint Eustatius is aandacht voor taal, cultuur, onderwijssystemen en afstand tot familie."}]},{"title":{"nl":"Hulpaanbod / dienstverlening"},"paragraphs":[{"nl":"Het aanbod bestaat uit residentiele behandeling en middagbehandeling. Residentiele behandeling is verdeeld in twee leefgroepen: Nos Kas 1 voor jeugdigen van 13-18 jaar en Nos Kas 2 voor jeugdigen van 8-12 jaar."},{"nl":"De middagbehandeling is gericht op basisschooljeugd die niet binnen reguliere naschoolse opvang past. In beide trajecten wordt een veilige en gestructureerde omgeving geboden waarin jeugdigen werken aan persoonlijke doelen."}]},{"title":{"nl":"Werkwijze en methodieken"},"paragraphs":[{"nl":"Stichting Project werkt met vier pijlers: traumasensitief werken, competentiegericht werken, geweldloos communiceren en verbindend gezag, en systeemgericht werken. Begeleiding krijgt vorm op drie niveaus: veiligheid, ontwikkeling en behandeling."},{"nl":"Traumasensitief werken betekent dat gedrag wordt begrepen vanuit ingrijpende ervaringen en dat veiligheid, voorspelbaarheid en begrip centraal staan. Competentiegericht werken richt zich op vaardigheden, zelfvertrouwen en handelingsvermogen. Geweldloos communiceren en verbindend gezag combineren duidelijke grenzen met verbinding. Systeemgericht werken kijkt naar gezin, familie, school en netwerk."}]},{"title":{"nl":"Trajectverloop en duur"},"paragraphs":[{"nl":"Een traject begint met aanmelding, waarin hulpvraag en benodigde ondersteuning worden onderzocht. Daarna start het hulpverleningsproces, waarin actief wordt gewerkt aan doelen uit het begeleidingsplan. Het traject sluit af met evaluatie en uitstroom naar huis of een andere vervolgplek."},{"nl":"De gemiddelde duur van een begeleidingstraject bedraagt ongeveer anderhalf jaar."}]},{"title":{"nl":"Verwijzing en toegankelijkheid"},"paragraphs":[{"nl":"Aanmelding voor residentiele behandeling verloopt altijd via ZJCN. Opname volgt wanneer de hulpvraag aansluit bij het zorgaanbod. Tijdens aanmelding wordt beoordeeld welke risico?s aanwezig zijn en of begeleiding en behandeling binnen Stichting Project kan worden geboden."},{"nl":"Voor middagbehandeling kan aanmelding worden gedaan door ZJCN of ketenpartners MHC, EOZ of Akseso."}]},{"title":{"nl":"Praktische informatie"},"paragraphs":[{"nl":"Bezoekadres: Bulevar Gobernador N. Debrot 218. Telefoon: 782-8481. E-mail: info@stichtingproject.com. Website: www.stichtingproject.com."}]},{"title":{"nl":"Samenwerkingspartners"},"paragraphs":[{"nl":"Stichting Project werkt samen met Akseso, MHC, Rosa di Sharon, Begeleid Wonen, ZJCN, Jong Bonaire en scholen. Het streven is meer samenhang in de keten, met een gedeelde taal en multidisciplinaire samenwerking."}]}]}') ON DUPLICATE KEY UPDATE slug = VALUES(slug), status = VALUES(status), source_status = VALUES(source_status), entity_type = VALUES(entity_type), visibility_public = VALUES(visibility_public), source_locked = VALUES(source_locked), review_flags_json = VALUES(review_flags_json), source_format_json = VALUES(source_format_json), legacy_sections_json = VALUES(legacy_sections_json);
INSERT INTO organizations (external_key, slug, status, source_status, entity_type, visibility_public, source_locked, review_flags_json, source_format_json, legacy_sections_json) VALUES ('org_guana_chat_918', 'guana-chat-918', 'published', 'demo', 'organisation', 1, 1, '{"needs_content_review":true,"replace_with_official_format_when_available":true,"opening_hours_verify_before_launch":true}', '{"general_information":{},"service_offer":{},"access_and_referral":{},"practical_information":{},"professional_information":{}}', '{"youth_sections":[],"professional_sections":[]}') ON DUPLICATE KEY UPDATE slug = VALUES(slug), status = VALUES(status), source_status = VALUES(source_status), entity_type = VALUES(entity_type), visibility_public = VALUES(visibility_public), source_locked = VALUES(source_locked), review_flags_json = VALUES(review_flags_json), source_format_json = VALUES(source_format_json), legacy_sections_json = VALUES(legacy_sections_json);
INSERT INTO organizations (external_key, slug, status, source_status, entity_type, visibility_public, source_locked, review_flags_json, source_format_json, legacy_sections_json) VALUES ('org_famia_fuerte', 'famia-fuerte', 'published', 'submitted', 'programme', 1, 1, NULL, NULL, '{"youth_sections":[{"title":{"nl":"Wie zijn wij?"},"paragraphs":[{"nl":"Famia Fuerte is een team van mensen die gezinnen helpen wanneer er thuis veel problemen zijn. Het team werkt samen met verschillende organisaties op Bonaire om kinderen en ouders te ondersteunen."}]},{"title":{"nl":"Voor wie zijn wij?"},"paragraphs":[{"nl":"Voor gezinnen die het moeilijk hebben en extra hulp nodig hebben, bijvoorbeeld wanneer er zorgen zijn over de veiligheid van kinderen of wanneer een kind misschien niet meer thuis kan wonen."}]},{"title":{"nl":"Waarmee kunnen wij helpen?"},"paragraphs":[{"nl":"Soms hebben gezinnen te maken met veel moeilijke situaties tegelijk, zoals problemen thuis, op school, met geld, gezondheid of hoe gezinsleden met elkaar omgaan."}],"items":["Weer rust en overzicht krijgen","Beter met elkaar omgaan","Problemen stap voor stap oplossen","Ervoor zorgen dat kinderen veilig thuis kunnen blijven wonen"]},{"title":{"nl":"Hoe kom je terecht?"},"paragraphs":[{"nl":"Je kunt je niet zelf aanmelden. Een hulpverlener van een samenwerkende organisatie bespreekt samen met het gezin of Famia Fuerte kan helpen."}]},{"title":{"nl":"Hoe helpen wij?"},"paragraphs":[{"nl":"Famia Fuerte komt bij het gezin thuis en kijkt samen wat nodig is. Er wordt gepraat met ouders en kinderen en er wordt een plan gemaakt dat past bij het gezin."}],"items":["Werken aan een veilige thuissituatie","Betere afspraken binnen het gezin","Problemen oplossen","Versterken wat al goed gaat"]},{"title":{"nl":"Hoelang duurt de hulp?"},"paragraphs":[{"nl":"De hulp bestaat meestal uit kennismaken, samen kijken naar problemen, werken aan verandering, vasthouden van vooruitgang en afronden. Gemiddeld duurt een traject ongeveer 1 tot 1,5 jaar."}]},{"title":{"nl":"Met wie werken wij samen?"},"items":["EOZ","Jeugdzorg","MHC","Akseso"]},{"title":{"nl":"Contact"},"paragraphs":[{"nl":"Tijdelijk bezoekadres: Kaya Korona 30. Op afspraak op woensdag tussen 08.00 en 17.00 uur. Aanmelding loopt via de aangesloten organisaties."}]}],"professional_sections":[{"title":{"nl":"Algemene informatie"},"paragraphs":[{"nl":"Famia Fuerte is een samenwerkingsverband tussen Jeugdzorg, EOZ, MHC en Akseso. Het hoofddoel is intensieve ambulante hulpverlening aan multiprobleemgezinnen."},{"nl":"De organisatie ondersteunt gezinnen bij het herstellen van balans, zodat gezinsleden veilig samen kunnen blijven wonen of kinderen verantwoord kunnen terugkeren naar huis. Het voorkomen van uithuisplaatsingen en bevorderen van een veilige thuissituatie staan centraal."}]},{"title":{"nl":"Doelgroep"},"paragraphs":[{"nl":"Gezinnen waarbij sprake is van een opeenstapeling van problemen op verschillende levensgebieden. De problematiek is complex, het gezin komt er zelf niet meer uit, er is sprake van onveiligheid van kinderen of kinderen dreigen uithuisgeplaatst te worden."}]},{"title":{"nl":"Hulpaanbod / dienstverlening"},"items":["Intensieve ambulante hulpverlening aan gezinnen","Praktische en opvoedkundige ondersteuning op maat","Begeleiding gericht op veiligheid en stabiliteit binnen het gezin","Ondersteuning bij versterken van sociaal netwerk en zelfredzaamheid"]},{"title":{"nl":"Werkwijze en methodieken"},"paragraphs":[{"nl":"Famia Fuerte werkt met VUHP en Signs of Safety. Het traject start met een integrale analyse van de gezinssituatie. Samen met gezin en betrokken professionals worden doelen opgesteld en afspraken gemaakt over rollen en verantwoordelijkheden."},{"nl":"De begeleiding richt zich op het doorbreken van langdurige en beschadigde gedrags- en gezinspatronen en het aanleren van nieuw en gewenst opvoedgedrag."}]},{"title":{"nl":"Trajectverloop en duur"},"paragraphs":[{"nl":"De duur hangt af van de complexiteit en doelen. Gemiddeld duurt een traject tussen de 1 en 1,5 jaar."}],"items":["Aanmeldingsfase","Startfase","Veranderfase","Stabilisatiefase","Overdrachts- en afrondingsfase"]},{"title":{"nl":"Verwijzing en toegankelijkheid"},"paragraphs":[{"nl":"Famia Fuerte is een tweede lijns hulpaanbod. Er moet een verwijzing van een professional zijn en Jeugdzorg moet betrokken zijn of zijn geweest. De vier samenwerkende organisaties kunnen aanmelden: EOZ, Jeugdzorg, Akseso of MHC."}]},{"title":{"nl":"Praktische informatie"},"paragraphs":[{"nl":"Er is geen eigen telefoonnummer en geen eigen website in de bron genoemd. Er is een e-mailadres voor aanmeldingen, maar dit kan alleen via de vier aangesloten organisaties. Tijdelijk bezoekadres: Kaya Korona 30, alleen op woensdagen op afspraak. Openingstijd: 08.00-17.00 uur op afspraak."}]},{"title":{"nl":"Samenwerkingspartners"},"paragraphs":[{"nl":"EOZ, Jeugdzorg, MHC en Akseso. Professionals kunnen contact opnemen met de verantwoordelijken voor Famia Fuerte bij de vier aangesloten organisaties."}]}]}') ON DUPLICATE KEY UPDATE slug = VALUES(slug), status = VALUES(status), source_status = VALUES(source_status), entity_type = VALUES(entity_type), visibility_public = VALUES(visibility_public), source_locked = VALUES(source_locked), review_flags_json = VALUES(review_flags_json), source_format_json = VALUES(source_format_json), legacy_sections_json = VALUES(legacy_sections_json);
INSERT INTO organizations (external_key, slug, status, source_status, entity_type, visibility_public, source_locked, review_flags_json, source_format_json, legacy_sections_json) VALUES ('org_begeleid_wonen_bonaire', 'begeleid-wonen-bonaire', 'published', 'submitted', 'programme', 1, 1, NULL, NULL, '{"youth_sections":[{"title":{"nl":"Wie zijn wij?"},"paragraphs":[{"nl":"Begeleid Wonen Bonaire helpt jongeren om stap voor stap zelfstandig te worden. BWB biedt een veilige basis waar jongeren kunnen leren, groeien en ontdekken wat zij zelf kunnen."}]},{"title":{"nl":"Voor wie zijn wij?"},"paragraphs":[{"nl":"BWB is er voor jongeren van 16 tot en met 23 jaar uit Bonaire, Sint Eustatius en Saba. Soms is zelfstandig wonen spannend of moeilijk en is extra hulp nodig om dingen zelf te leren regelen."}]},{"title":{"nl":"Waarmee kunnen wij helpen?"},"items":["Leren wonen in een begeleide woonplek","Persoonlijke gesprekken en begeleiding","Hulp terwijl je thuis of zelfstandig woont","Leren koken, schoonmaken en plannen","Omgaan met geld en leren sparen","Ondersteuning bij school, werk of dagbesteding","Hulp als je op jezelf gaat wonen"]},{"title":{"nl":"Hoe kom je terecht?"},"paragraphs":[{"nl":"Je kunt niet zelf een plek bij BWB aanvragen. Een aanmelding verloopt via Zorg en Jeugd Caribisch Nederland (ZJCN). Samen met jouw jeugdzorgbegeleider wordt gekeken of BWB bij jou past."}]},{"title":{"nl":"Hoe helpen wij?"},"paragraphs":[{"nl":"Iedere jongere is anders. Daarom maakt BWB samen met jou een plan dat past bij jouw situatie en doelen. Het doel is dat je steeds meer vertrouwen krijgt in jezelf en zo zelfstandig mogelijk kunt leven."}],"items":["Stap 1: leren en oefenen met dagelijkse vaardigheden","Stap 2: zelf doen en meer verantwoordelijkheid krijgen","Stap 3: op eigen benen en eventueel nazorg krijgen"]},{"title":{"nl":"Hoelang duurt de hulp?"},"paragraphs":[{"nl":"Gemiddeld duurt een traject bij BWB ongeveer drie jaar. De duur hangt af van jouw ontwikkeling, wat je nodig hebt en de doelen waaraan je werkt."}]},{"title":{"nl":"Met wie werken wij samen?"},"items":["Zorg en Jeugd Caribisch Nederland (ZJCN)","Jeugdzorg Caribisch Nederland","Scholen en opleidingen","Werkgevers en stageplekken","Organisaties voor dagbesteding","Ouders, verzorgers en belangrijke mensen uit jouw omgeving"]},{"title":{"nl":"Contact"},"paragraphs":[{"nl":"Telefoon: 00599-7955055. E-mail: frida.windster@jeugdzorgcn.cm. Adres: Kaya Mendelssohn 20A."}]}],"professional_sections":[{"title":{"nl":"Algemene informatie"},"paragraphs":[{"nl":"Begeleid Wonen Bonaire ondersteunt jongeren bij de overgang naar een zelfstandig bestaan. Door begeleiding op maat helpt BWB jongeren vaardigheden ontwikkelen die nodig zijn om zelfstandig en verantwoord te functioneren in de samenleving."},{"nl":"Zelfredzaamheid, eigen regie en maatschappelijke participatie staan centraal. BWB wil jongeren een veilige basis bieden van waaruit zij groeien naar een zelfstandige toekomst."}]},{"title":{"nl":"Doelgroep"},"paragraphs":[{"nl":"Jongeren van 16 tot en met 23 jaar afkomstig van Bonaire, Sint Eustatius en Saba die vanuit jeugdzorg ondersteuning nodig hebben bij de overgang naar zelfstandig wonen. Het gaat om jongeren die nog niet volledig zelfstandig kunnen functioneren."}]},{"title":{"nl":"Hulpaanbod / dienstverlening"},"items":["Begeleid wonen","Individuele begeleiding","Ambulante begeleiding","Training in zelfstandigheidsvaardigheden","Ondersteuning bij budgettering en omgaan met geld","Begeleiding bij school, werk en dagbesteding","Nazorg na uitstroom naar zelfstandig wonen"]},{"title":{"nl":"Werkwijze en methodieken"},"paragraphs":[{"nl":"BWB werkt fasegericht volgens de ACA-methodiek: aansturen, coachen en adviseren. Daarnaast wordt gebruikgemaakt van competentiegericht begeleiden en Family Functional Patrol (FFP). De begeleiding is maatwerk en sluit aan bij mogelijkheden, behoeften en ontwikkeldoelen van iedere jongere."}]},{"title":{"nl":"Trajectverloop en duur"},"paragraphs":[{"nl":"De gemiddelde duur van een traject bedraagt ongeveer drie jaar. De uiteindelijke duur hangt af van ontwikkeling, motivatie en individuele hulpvraag."}],"items":["Aanleren van basisvaardigheden","Vergroten van zelfstandigheid","Doorstroom naar zelfstandig wonen met ambulante begeleiding en nazorg"]},{"title":{"nl":"Verwijzing en toegankelijkheid"},"paragraphs":[{"nl":"Aanmelding bij BWB verloopt uitsluitend via ZJCN. De jongere moet onder begeleiding van Jeugdzorg staan en een hulpvraag hebben die gericht is op vergroten van zelfstandigheid en toewerken naar zelfstandig wonen."}]},{"title":{"nl":"Praktische informatie"},"paragraphs":[{"nl":"Adres: Kaya Mendelssohn 20A. Telefoon: +599 795 5055. E-mail: frida.windster@jeugdzorgcn.cm."}]},{"title":{"nl":"Samenwerkingspartners"},"paragraphs":[{"nl":"BWB werkt samen met Jeugdzorg CN, FCB, scholen, werkgevers, GGZ en andere relevante ketenpartners."}]}]}') ON DUPLICATE KEY UPDATE slug = VALUES(slug), status = VALUES(status), source_status = VALUES(source_status), entity_type = VALUES(entity_type), visibility_public = VALUES(visibility_public), source_locked = VALUES(source_locked), review_flags_json = VALUES(review_flags_json), source_format_json = VALUES(source_format_json), legacy_sections_json = VALUES(legacy_sections_json);
