INSERT INTO organization_translations (organization_id, language_code, name, youth_title, youth_short, youth_where_can_you_go, youth_how_it_works, professional_summary, professional_referral_or_access, professional_notes, type_label, age_range, translation_status) VALUES ((SELECT id FROM organizations WHERE external_key = 'org_akseso'), 'nl', 'Sentro Akseso Boneiru', 'Sentro Akseso Boneiru', 'Akseso luistert naar wat er speelt en zoekt samen met jou of je gezin naar passende hulp.', 'Je kunt bij Akseso terecht met vragen over thuis, opvoeden, geld, verdriet, ruzie, veiligheid, gezondheid of andere zorgen.', 'Je kunt zelf contact opnemen. Ook een ouder, school, huisarts of hulpverlener kan je aanmelden.', 'Sentro Akseso Boneiru is het centrale toegangspunt voor sociale hulpverlening, preventie en ondersteuning op Bonaire.', 'Vrij toegankelijk voor inwoners van Bonaire. Professionals kunnen cliënten aanmelden of overleggen over passende ondersteuning.', 'Demo-informatie; inhoud en verwijscriteria moeten voor lancering worden bevestigd.', 'Centraal toegangspunt / sociale hulpverlening', 'Kinderen, jongeren, ouders, gezinnen, volwassenen en professionals', 'published') ON DUPLICATE KEY UPDATE name = VALUES(name), youth_title = VALUES(youth_title), youth_short = VALUES(youth_short), youth_where_can_you_go = VALUES(youth_where_can_you_go), youth_how_it_works = VALUES(youth_how_it_works), professional_summary = VALUES(professional_summary), professional_referral_or_access = VALUES(professional_referral_or_access), professional_notes = VALUES(professional_notes), type_label = VALUES(type_label), age_range = VALUES(age_range), translation_status = VALUES(translation_status);
