INSERT INTO organization_profile_answers (organization_id, audience_code, group_key, field_key, language_code, answer_text, answer_format, translation_status, source_locked, sort_order) VALUES ((SELECT id FROM organizations WHERE external_key = 'org_akseso'), 'professional', 'additional', 'other_information', 'nl', 'Akseso fungeert als centraal toegangspunt voor sociale hulpverlening op Bonaire. De organisatie werkt multidisciplinair en integraal, met nadruk op preventie, vroegsignalering en versterking van gezinnen. Professionals kunnen cli?nten rechtstreeks aanmelden of overleggen over passende ondersteuning.', 'plain_text', 'published', 1, 18) ON DUPLICATE KEY UPDATE answer_text = VALUES(answer_text), answer_format = VALUES(answer_format), translation_status = VALUES(translation_status), source_locked = VALUES(source_locked), sort_order = VALUES(sort_order);
