INSERT INTO organization_translations (organization_id, language_code, name, youth_title, youth_short, youth_where_can_you_go, youth_how_it_works, professional_summary, professional_referral_or_access, professional_notes, type_label, age_range, translation_status) VALUES ((SELECT id FROM organizations WHERE external_key = 'org_zjcn'), 'nl', 'Zorg en Jeugd Caribisch Nederland (ZJCN) - Afdeling Jeugdzorg', 'ZJCN Jeugdzorg', 'ZJCN Jeugdzorg helpt kinderen, jongeren en gezinnen die extra steun nodig hebben om veilig op te groeien.', 'Zorg en Jeugd Caribisch Nederland kan helpen als er meer ondersteuning nodig is voor jou of je gezin.', 'Je kunt via huisarts, school, Guiami of Akseso terechtkomen, of zelf langskomen tijdens inloopuren.', 'De afdeling Jeugdzorg van ZJCN zet zich in om de positie van kinderen op Bonaire, Saba en Sint Eustatius te verbeteren.', 'Verwijzing is mogelijk via huisarts, school, Guiami of Akseso. Mensen kunnen ook zelf langskomen tijdens de inloopuren.', 'Demo-informatie; inhoud en verwijscriteria moeten voor lancering worden bevestigd.', 'Jeugdzorg / gezinsondersteuning', 'Kinderen, jongeren en gezinnen op Bonaire, Saba en Sint Eustatius', 'published') ON DUPLICATE KEY UPDATE name = VALUES(name), youth_title = VALUES(youth_title), youth_short = VALUES(youth_short), youth_where_can_you_go = VALUES(youth_where_can_you_go), youth_how_it_works = VALUES(youth_how_it_works), professional_summary = VALUES(professional_summary), professional_referral_or_access = VALUES(professional_referral_or_access), professional_notes = VALUES(professional_notes), type_label = VALUES(type_label), age_range = VALUES(age_range), translation_status = VALUES(translation_status);
