INSERT INTO organization_translations (organization_id, language_code, name, youth_title, youth_short, youth_where_can_you_go, youth_how_it_works, professional_summary, professional_referral_or_access, professional_notes, type_label, age_range, translation_status) VALUES ((SELECT id FROM organizations WHERE external_key = 'org_mhc'), 'nl', 'Mental Health Caribbean (MHC) / Kind & Jeugd / Hi-5', 'MHC Kind & Jeugd / Hi-5', 'MHC helpt kinderen, jongeren en gezinnen als gevoelens, gedachten of gedrag zorgen geven.', 'Als je veel angst, somberheid, boosheid, stress of andere psychische klachten ervaart, kan Mental Health Caribbean (MHC) helpen.', 'Voor hulp bij MHC heb je een verwijzing nodig van de huisarts of kinderarts.', 'MHC Kind & Jeugd biedt ambulante diagnostiek, behandeling en begeleiding voor kinderen en jeugdigen met psychische of psychiatrische kwetsbaarheid of problematiek.', 'Voor behandeling is een verwijzing van huisarts of kinderarts nodig. Aanmelding loopt via de Bureaudienst voor intakeplanning.', 'Demo-informatie; inhoud en verwijscriteria moeten voor lancering worden bevestigd.', 'Geestelijke gezondheidszorg kind en jeugd', 'Kinderen en jongeren van 0 tot 18 jaar en hun gezin', 'published') ON DUPLICATE KEY UPDATE name = VALUES(name), youth_title = VALUES(youth_title), youth_short = VALUES(youth_short), youth_where_can_you_go = VALUES(youth_where_can_you_go), youth_how_it_works = VALUES(youth_how_it_works), professional_summary = VALUES(professional_summary), professional_referral_or_access = VALUES(professional_referral_or_access), professional_notes = VALUES(professional_notes), type_label = VALUES(type_label), age_range = VALUES(age_range), translation_status = VALUES(translation_status);
