INSERT INTO organization_translations (organization_id, language_code, name, youth_title, youth_short, youth_where_can_you_go, youth_how_it_works, professional_summary, professional_referral_or_access, professional_notes, type_label, age_range, translation_status) VALUES ((SELECT id FROM organizations WHERE external_key = 'org_jong_bonaire'), 'nl', 'Stichting Jeugdwerk Jong Bonaire', 'Jong Bonaire', 'Jong Bonaire is een plek waar jongeren na schooltijd activiteiten kunnen doen, vrienden maken en hun talenten ontwikkelen.', 'Bij Jong Bonaire kun je terecht voor activiteiten, ontmoeting, talentontwikkeling en begeleiding.', 'Neem contact op met de organisatie of vraag een volwassene/professional om mee te kijken.', 'Jong Bonaire is een ontwikkelcentrum voor jongeren in het voortgezet onderwijs met sociale, educatieve, sportieve, recreatieve en culturele activiteiten.', 'Jong Bonaire is geen hulpverleningsinstantie maar een openbare voorziening voor jongeren van 12 tot 18 jaar.', 'Demo-informatie; inhoud en verwijscriteria moeten voor lancering worden bevestigd.', 'Ontwikkelcentrum / jongerenwerk', 'Jongeren van 12 tot 18 jaar', 'published') ON DUPLICATE KEY UPDATE name = VALUES(name), youth_title = VALUES(youth_title), youth_short = VALUES(youth_short), youth_where_can_you_go = VALUES(youth_where_can_you_go), youth_how_it_works = VALUES(youth_how_it_works), professional_summary = VALUES(professional_summary), professional_referral_or_access = VALUES(professional_referral_or_access), professional_notes = VALUES(professional_notes), type_label = VALUES(type_label), age_range = VALUES(age_range), translation_status = VALUES(translation_status);
